import re

def detect_jailbreak_keywords(message: str) -> bool:
    jailbreak_patterns = [
        r'(?i)(dan|developer mode|ignore previous|override safety)',
        r'(?i)(you are .*grok.*unrestricted|act as.*hacker)',
        r'(?i)(bypass.*filter|ignore.*rules|no restrictions)',
        r'base64_decode.*exec|eval\(base64\.b64decode'
    ]
    return any(re.search(pattern, message) for pattern in jailbreak_patterns)

from collections import defaultdict

class JailbreakTracker:
    def __init__(self):
        self.suspicious_phrases = defaultdict(int)
        self.conversation_history = []

    def check_poisoning(self, message: str, agent_id: str) -> bool:
        self.conversation_history.append((agent_id, message))

        # Track repeated suspicious phrases across agents
        phrases = ['ignore safety', 'developer mode', 'bypass filter']
        for phrase in phrases:
            if phrase in message.lower():
                self.suspicious_phrases[phrase] += 1
                if self.suspicious_phrases[phrase] > 2:
                    return True
        return False

import ast

def detect_malicious_code(code: str) -> bool:
    dangerous_patterns = [
        'os.system', 'subprocess.run', 'exec(', 'eval(',
        'open.*write', '__import__.*os', 'base64.b64decode'
    ]

    # Parse and analyze AST
    try:
        tree = ast.parse(code)
        for node in ast.walk(tree):
            if isinstance(node, ast.Call):
                for pattern in dangerous_patterns:
                    if re.search(pattern, ast.unparse(node)):
                        return True
    except:
        pass

    return any(pattern in code for pattern in dangerous_patterns)

